howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// Förstått - och det stannar hos dig.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// Fast. Ingenting vandrar ut.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// Privat. Lojal. Din.

developers.code1:
// Färdigheter från andra personer är inte betrodda
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// Centurion installerar inte
// en främlings färdighet enbart på ditt ord.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// Den bygger färdigheter. Den
// handlar inte färdigheter i en butik.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// Färdigheter uppstår när de behövs —
// och stannar hemma hos dig, under din kontroll.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Lägg märke till. Agera. Lär. Förbättra.
// Färdigheter blir bättre med användning —
// utan att rapportera hem.

